import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a bond?", a: "A bond is a loan made to a company, government, or other issuer. The issuer usually pays interest and returns the face value at maturity." },
  { q: "What is yield to maturity?", a: "Yield to maturity is the annualized return an investor may earn if the bond is held until maturity and all payments are received as expected." },
  { q: "What is the relationship between bond price and yield?", a: "Bond prices and yields move in opposite directions. When market prices fall, yield rises; when prices rise, yield falls." },
  { q: "What is a coupon rate?", a: "The coupon rate is the annual interest rate paid on the bond's face value." },
  { q: "What is the difference between corporate and government bonds?", a: "Corporate bonds are issued by companies and often carry more credit risk. Government bonds are issued by governments and may be considered safer depending on the issuer." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function bondPrice(face: number, couponRate: number, years: number, ytm: number, freq: number) {
  const periods = Math.max(1, Math.round(years * freq));
  const c = face * (couponRate / 100) / freq;
  const r = ytm / 100 / freq;
  if (r === 0) return c * periods + face;
  return c * (1 - Math.pow(1 + r, -periods)) / r + face / Math.pow(1 + r, periods);
}

function estimateYTM(face: number, couponRate: number, years: number, freq: number, price: number) {
  let low = -50;
  let high = 100;
  for (let i = 0; i < 80; i++) {
    const mid = (low + high) / 2;
    const p = bondPrice(face, couponRate, years, mid, freq);
    if (p > price) low = mid;
    else high = mid;
  }
  return (low + high) / 2;
}

export default function BondCalculator() {
  useCurrencyVersion();
  const [face, setFace] = useState(10000);
  const [coupon, setCoupon] = useState(5);
  const [years, setYears] = useState(10);
  const [frequency, setFrequency] = useState(2);
  const [marketPrice, setMarketPrice] = useState(9800);
  const result = useMemo(() => {
    const ytm = estimateYTM(face, coupon, years, frequency, marketPrice);
    const annualCoupon = face * coupon / 100;
    const currentYield = annualCoupon / marketPrice * 100;
    const totalInterest = annualCoupon * years;
    const priceAtYtm = bondPrice(face, coupon, years, ytm, frequency);
    const schedule = Array.from({ length: Math.min(Math.round(years * frequency), 80) }, (_, i) => ({ period: i + 1, coupon: annualCoupon / frequency, principal: i + 1 === Math.round(years * frequency) ? face : 0 }));
    return { ytm, currentYield, totalInterest, priceAtYtm, schedule };
  }, [face, coupon, years, frequency, marketPrice]);
  const comparison = [2, 3, 4, 5, 6].map((rate) => ({ rate, y5: rate, y10: rate, y20: rate, income: 10000 * rate / 100 }));

  return (
    <>
      <SEOHead title="Free Bond Calculator Online - Calculate Bond Yield and Price Instantly | CalcHive" description="Free online bond calculator. Calculate bond yield to maturity, current yield, price and total interest income for any bond instantly. 100% free, no signup required." canonical="/bond-calculator" keywords="free bond calculator, bond yield calculator free online, yield to maturity calculator free, bond price calculator free, fixed income calculator free online" category="Financial Calculators" breadcrumbName="Free Bond Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Bond Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate bond yield to maturity, current yield, price, and coupon income.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Face value</label><input type="number" value={face} onChange={(e) => setFace(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Coupon rate (%)</label><input type="number" value={coupon} onChange={(e) => setCoupon(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Years to maturity</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Coupon frequency</label><select value={frequency} onChange={(e) => setFrequency(Number(e.target.value))} className={inputClass}><option value={1}>Annual</option><option value={2}>Semiannual</option><option value={4}>Quarterly</option></select></div>
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Market price</label><input type="number" value={marketPrice} onChange={(e) => setMarketPrice(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Yield to Maturity</p><p className="text-5xl sm:text-6xl font-black text-white">{result.ytm.toFixed(2)}%</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Current yield</p><p className="text-lg font-extrabold text-foreground">{result.currentYield.toFixed(2)}%</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest income</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Bond price</p><p className="text-lg font-extrabold text-foreground">{money(result.priceAtYtm)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Bond Yield to Maturity for Free</h2><p className="text-muted-foreground leading-relaxed">This fixed income calculator estimates the discount rate that makes the bond's future coupon and face value payments equal to today's market price.</p>
          <h2 className="text-2xl font-bold text-foreground">How Bond Price and Yield Are Related</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Bond Yield Comparison by Coupon Rate and Maturity</caption><thead className="bg-muted/60"><tr>{["Coupon Rate", "5 Year YTM at Par", "10 Year YTM at Par", "20 Year YTM at Par", "Annual Income on $10K"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.rate}><td className="py-2.5 px-3 font-semibold">{row.rate}%</td><td className="py-2.5 px-3">{row.y5}%</td><td className="py-2.5 px-3">{row.y10}%</td><td className="py-2.5 px-3">{row.y20}%</td><td className="py-2.5 px-3">{money(row.income)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Fixed Income Bond Calculator for Investors</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Coupon Payment Schedule</caption><thead className="bg-muted/60"><tr>{["Period", "Coupon Payment", "Principal Return", "Total Cash Flow"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.schedule.map((row) => <tr key={row.period}><td className="py-2.5 px-3">{row.period}</td><td className="py-2.5 px-3">{money(row.coupon)}</td><td className="py-2.5 px-3">{money(row.principal)}</td><td className="py-2.5 px-3">{money(row.coupon + row.principal)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/bond-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


